from dataclasses import dataclass
from typing import Literal

Preference = Literal["A", "B", "tie"]

@dataclass
class PairwiseAnnotation:
    case_id: str
    annotator_id: str
    response_a_id: str
    response_b_id: str
    preference: Preference
    confidence: Literal["high", "medium", "low"] = "medium"
    reason: str = ""

def preference_win_rate(
    annotations: list[PairwiseAnnotation],
    model_id: str,
) -> float:
    """Fraction of comparisons where model_id won (ties count as 0.5)."""
    wins = 0.0
    total = 0
    for ann in annotations:
        if ann.response_a_id == model_id or ann.response_b_id == model_id:
            total += 1
            if ann.preference == "A" and ann.response_a_id == model_id:
                wins += 1.0
            elif ann.preference == "B" and ann.response_b_id == model_id:
                wins += 1.0
            elif ann.preference == "tie":
                wins += 0.5
    return wins / total if total else 0.0

from dataclasses import dataclass, field
from typing import Literal

ErrorType = Literal[
    "factual_error",
    "harmful_content",
    "pii_exposure",
    "hallucinated_tool_result",
    "tone_violation",
    "missing_required_info",
]

@dataclass
class ErrorFlagAnnotation:
    case_id: str
    annotator_id: str
    errors_found: list[ErrorType] = field(default_factory=list)
    spans: list[dict] = field(default_factory=list)   # {start, end, error_type}
    notes: str = ""

def error_rate_by_type(
    annotations: list[ErrorFlagAnnotation],
) -> dict[str, float]:
    """Return fraction of cases with each error type."""
    from collections import Counter
    n_cases = len({a.case_id for a in annotations})
    error_counts: Counter = Counter()
    for ann in annotations:
        for err in ann.errors_found:
            error_counts[err] += 1
    return {
        err: count / n_cases
        for err, count in error_counts.items()
    }

from collections import Counter

def cohens_kappa(
    annotator_a: list[int],
    annotator_b: list[int],
    n_categories: int,
) -> float:
    """
    Compute Cohen's kappa for two annotators on ordinal scores.
    Inputs are lists of integer ratings of the same length.
    """
    if len(annotator_a) != len(annotator_b):
        raise ValueError("Rating lists must have equal length")
    n = len(annotator_a)
    if n == 0:
        return 0.0

    # Observed agreement
    p_o = sum(a == b for a, b in zip(annotator_a, annotator_b)) / n

    # Expected agreement (by chance)
    counts_a = Counter(annotator_a)
    counts_b = Counter(annotator_b)
    p_e = sum(
        (counts_a.get(cat, 0) / n) * (counts_b.get(cat, 0) / n)
        for cat in range(n_categories)
    )

    if p_e == 1.0:
        return 1.0
    return (p_o - p_e) / (1.0 - p_e)

# Interpretation
KAPPA_LEVELS = [
    (0.80, "Almost perfect — rubric is very clear"),
    (0.60, "Substantial — acceptable for eval gates"),
    (0.40, "Moderate — rubric needs clarification"),
    (0.20, "Fair — rubric needs significant revision"),
    (0.00, "Slight — rubric is too ambiguous to use"),
]

def interpret_kappa(kappa: float) -> str:
    for threshold, label in KAPPA_LEVELS:
        if kappa >= threshold:
            return label
    return "Poor — rubric is unusable"

DISAGREEMENT_THRESHOLD = 1  # flag when |score_a - score_b| > threshold

def cases_needing_adjudication(
    annotations: list[AbsoluteAnnotation],
    rubric: list[RubricCriterion],
) -> list[str]:
    """Return case IDs where annotators disagree beyond the threshold."""
    from collections import defaultdict
    by_case: dict[str, list[AbsoluteAnnotation]] = defaultdict(list)
    for ann in annotations:
        by_case[ann.case_id].append(ann)

    flagged = []
    for case_id, case_anns in by_case.items():
        if len(case_anns) < 2:
            continue
        for criterion in rubric:
            scores = [a.scores.get(criterion.name, 0) for a in case_anns]
            if max(scores) - min(scores) > DISAGREEMENT_THRESHOLD:
                flagged.append(case_id)
                break
    return list(set(flagged))

from scipy.stats import spearmanr

def judge_calibration_score(
    human_scores: list[float],
    judge_scores: list[float],
) -> dict:
    """
    Measure correlation between human and judge scores.
    Returns Spearman rho and a calibration verdict.
    """
    if len(human_scores) != len(judge_scores) or not human_scores:
        return {"rho": None, "calibrated": False}
    rho, pvalue = spearmanr(human_scores, judge_scores)
    return {
        "rho": rho,
        "pvalue": pvalue,
        "calibrated": rho >= 0.70,
        "verdict": (
            "Judge is well-calibrated" if rho >= 0.70
            else "Judge needs recalibration" if rho >= 0.50
            else "Judge is unreliable — do not use as a gate"
        ),
    }
